-- Product registration child table RLS migration
-- Logical scope: 017_product_registration_child_table_rls.sql
-- Generated by Supabase CLI as 20260701122421_product_registration_child_table_rls.sql.
--
-- Purpose:
-- - Add narrowly scoped RLS policies for product registration child tables.
-- - Keep product child tables usable only through approved public projections,
--   Supplier owner draft/submission management, or Admin review.
--
-- Safety:
-- - No production data mutation.
-- - No broad authenticated-only policies.
-- - No DELETE policies.
-- - No new SECURITY DEFINER helper functions.
-- - No public price, Buyer PII, or Supplier-Buyer direct contact exposure.
-- - Storage bucket policies are not changed in this migration.

begin;

alter table public.product_images enable row level security;
alter table public.product_documents enable row level security;
alter table public.product_certificates enable row level security;
alter table public.product_registration_fields enable row level security;
alter table public.product_registration_values enable row level security;

