create policy product_images_public_select
on public.product_images
for select
to anon, authenticated
using (
  deleted_at is null
  and approval_status = 'approved'
  and visibility = 'public'
  and exists (
    select 1
    from public.products
    where products.id = product_images.product_id
      and products.approval_status = 'approved'
      and products.publish_status = 'published'
      and products.is_active = true
      and products.deleted_at is null
  )
);

create policy product_images_supplier_owner_select
on public.product_images
for select
to authenticated
using (
  deleted_at is null
  and exists (
    select 1
    from public.products
    where products.id = product_images.product_id
      and products.supplier_id = public.current_supplier_id()
      and products.deleted_at is null
  )
);

create policy product_images_supplier_owner_insert
on public.product_images
for insert
to authenticated
with check (
  approval_status in ('draft', 'submitted', 'reviewing')
  and visibility in ('public', 'restricted')
  and exists (
    select 1
    from public.products
    where products.id = product_images.product_id
      and products.supplier_id = public.current_supplier_id()
      and products.deleted_at is null
  )
  and exists (
    select 1
    from public.files
    where files.id = product_images.file_id
      and files.owner_profile_id = auth.uid()
      and files.bucket = 'product-files'
      and files.is_active = true
      and files.deleted_at is null
  )
);

